import{o as p,e as t,D as a}from"./framework.f0c4128f.js";const e='{"title":"Глава 5","description":"","frontmatter":{"title":"Глава 5","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-10-10T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/5.md","lastUpdated":1624912580419}',r={},i=a("<p>Шива сказал:</p><p>Теперь поведаю, о Владычица, о расположении миров. В начале (пребывает) очищающий мир Калагни, (затем), три (мира) авичи - Кумбипака, Раурава и Кушманда. Все эти миры чисты, нет в том сомнения ..1-2.</p><p>Затем следуют семь патал. Из них первая - Махатала. Затем - расатала, талатала, сутала, нитала, витала и тала. Все они описываются чистыми и золотыми ..3-4.</p><p>Выше этого - Земля, наделенная семью островами. В центре ее находится Меру - обитель богов ..5.</p><p>Выше ее бхувалока, над нею - сваргалока, далее маха, джана, тапа и сатья (локи). Такова семерка миров ..6.</p><p>(Существует) четырнадцать видов существ, в которых и действует сонм существ неподвижных, рожденных зверями, змеями и птицами. Они именуются пятью видами животных. Человек - иное. Пишачи, ракшасы, якши, гандхарвы, Индра, Сома, Праджапати, Брахма. (итого): четырнадцать. Все они чистые в мире Брахмы. (Выше) него - мир Вишну, еще выше - Мой мир. В той чистоте чисто все, без сомнения ..7-10.</p><p>О, Возлюбленная, благодаря этим чистым пяти мирам, начиная Калагни, все во вселенной становится чистым ..11.</p><p>Снаружи их находятся по отдельности миры ста рудр, (в которых) один владыка очищает десяток (миров) ..12.</p><p>Первый - Ананта, затем - Капалиша, Агнирудра, Яма, Нрти, Бала, Шигхра, Нидхишвара, Видхумадджаваланапрабха, .13-14.</p><p>Этой десяткой чистых очищается сотня. Выше предыдущих находится пять восьмерок (Рудр) ..15.</p><p>Лакули, Бхарабхути, Диндьяшадхи, Пушкара, Наймиша, Прабхаса, Амареша: такова (первая) восьмерка ..16.</p><p>Это называется восьмеркой господ. Теперь (рассказывается) тайна тайн. Это - Бхайрава, Кедара, Махакала, Мадхьяма, Амратикеша, Джалпеша, Шри Шайла, Хариндрава, Бхимешвара, Махендра, Адрихаса, Вималешвара, Канакхала, Накхала, Курукшетра, Гая: это третья, тайная (восьмерка). Теперь называется очищающая (восьмерка): Стхану, Суварна, Акшака, Вадйа, Бхадрага, Карнака, Махакала, Вимуктеша, Рудракоти, Амбарапада ..17-20.</p><p>Далее (следуют): Стхула, Стхулешвара, Шанкукарнака, Аланджара, Мандалешвара, Макота, Дуранда, Чхага, Ландака. Это именуется восьмеркой тела, пребывающей в ахамкаре. Выслушай о восьмерке источника богов в буддхи, описанную Мною ..21-22.</p><p>Пайшача, Ракшас, Якша, Гандхарва, Чайндра, Саумья, Прапджеша и Борахма: такова эта восьмерка ..23.</p><p>Восьмерка йоги (находится) в прадхане. Там в начале происходит творение. Крита, Вайбхава, Брахма, Вайшнава, Каумара, Аума, Шрайкантха: такова восьмерка йоги. В Пуруше (пребывают) Вама, Бхима, Угра, Бхава, Ишана, Экавира, Прачанда и Магхава. Далее, в видья (таттве) пребывают (распространяя) повсюду свет: Аджа, Аната, Экашива, Кродха и Чанда. В калА таттве известны Сурапа, Антака, Экавира, Шикханди, Иша, Шрикантха, охваченные Временем ..24-26.</p><p>Ничиная с Махатеджаса (пребывают) Мандалешана, далее следуют Вамадева, Бхава и Утбхава. Эти (миры) находятся в майататтве ..27.</p><p>Экапингекшана, Ишана, Бхуванеша, Ангуштхаматра и Каланала -эти пять миров один за другим известны мудрым, (как пребывающие) в видья таттве. Начиная с Халахалы, далее следуют Кродха, Рудра, Амбика, Агхора и Вамадева, (пребывающие) в Ишвара (таттве). Существующие миры завершаются на Агхоре есть великие владыки это - Раудри, Джештха, Вама, Шакти и Садашива. Эти пять миров известны мудрым в сакале ..28-32.</p><p>Итак, во всех таттвах известно 108 миров, описанных вкратце, а не подробно ..33.</p><p>Своей чистотою, они все очищают, без сомнения. Великомудрый, делая все пути чистыми, очищаясь в сакале пусть установит единство с Шивой. Знающий йогу и желающий наслаждения, пусть практикует йогу, созерцая сакалу. Таков этот путь миров провозглашенный Мною ..34-35. [small]Такова в священной «Малини виджайоттара тантре» пятая глава.[/small]</p>",19);r.render=function(a,e,r,l,s,_){return p(),t("div",null,[i])};export default r;export{e as __pageData};
